package com.mockmate.ai;
import com.mockmate.interview.InterviewType; import java.util.*; import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty; import org.springframework.stereotype.Service;

/** Deterministic fallback that keeps the app usable until OPENAI_API_KEY is configured. */
@Service @ConditionalOnProperty(name="app.openai.enabled", havingValue="false", matchIfMissing=true) public class LocalAiInterviewService implements AiInterviewService {
 public List<String> generateQuestions(InterviewType t,String role,String resume,int count){ List<String> bank=switch(t){case HR->List.of("Tell me about yourself and why you want this role.","Describe a challenging team situation and how you handled it.","What motivates you at work?");case JAVA->List.of("Explain the difference between HashMap and ConcurrentHashMap.","How does garbage collection work in Java?", "Explain SOLID principles with a practical example.");case DSA->List.of("How would you find the first non-repeating character in a string?", "Compare BFS and DFS and state their time complexity.","Design an efficient algorithm to detect a cycle in a linked list.");case TECHNICAL->List.of("Describe a REST API you built and its error-handling strategy.","How would you design a scalable authentication service?", "Explain database indexing trade-offs.");}; return bank.stream().limit(Math.max(1,Math.min(count,bank.size()))).toList(); }
 public Evaluation evaluate(InterviewType type,String q,String a){int words=a==null?0:a.trim().split("\\s+").length;int score=Math.min(100,Math.max(20,words*3+(a!=null&&a.toLowerCase().contains("example")?15:0)));String feedback=words<25?"Add more structure, technical detail, and a concrete example.":"Good foundation. Make the impact and trade-offs more explicit.";return new Evaluation(score,feedback,words<25?List.of("Answer depth","Concrete examples"):List.of("Quantifying impact"));}
}
